import React from "react";

const certificates = [
	{
		src: "/js.jpg",
		alt: "JavaScript Certificate",
		label: "JavaScript Certificate",
	},
	// Add more certificates here as needed
];

function Certification() {
	return (
		<section className="mt-10 animate-fade-in delay-800">
			<h2 className="text-2xl font-semibold mb-2">
				Achievements & Certificates
			</h2>
			<div className="flex flex-wrap gap-4">
				{certificates.map((cert, idx) => (
					<a
						key={idx}
						href={cert.src}
						target="_blank"
						rel="noopener noreferrer"
						className="cursor-zoom-in"
						style={{ display: "inline-block" }}
					>
						<img
							src={cert.src}
							alt={cert.alt}
							className="w-40 h-28 object-cover rounded shadow hover:scale-105 transition-transform duration-300"
						/>
						<div className="text-center mt-1 text-sm text-gray-300">
							{cert.label}
						</div>
					</a>
				))}
			</div>
			<p className="text-gray-400 mt-2 text-sm">
				Upload your certificates to <code>public/</code> as{" "}
				<code>js.jpg</code>, etc.
			</p>
		</section>
	);
}

export default Certification;
